import { redirect } from "next/navigation";
import { getCurrentUser } from "@/lib/session";
import { Award, TrendingUp } from "lucide-react";
import Link from "next/link";

export default async function ProfilePage() {
  const user = await getCurrentUser();
  if (!user) {
    redirect("/login");
  }

  const displayName = user.displayName ?? user.name;

  return (
    <div className="max-w-3xl mx-auto px-4 py-6 sm:pt-6">
      <div className="bg-white rounded-lg p-6 shadow-sm border border-[#d8d9db] mb-6">
        <div className="flex items-start gap-4 mb-6">
          {user.avatarUrl ? (
            <img
              src={user.avatarUrl}
              alt=""
              className="w-20 h-20 rounded-full object-cover"
            />
          ) : (
            <span className="flex h-20 w-20 shrink-0 items-center justify-center rounded-full bg-[#5b6880] text-2xl font-medium text-white">
              {displayName
                .split(" ")
                .map((n) => n[0])
                .join("")
                .toUpperCase()
                .slice(0, 2)}
            </span>
          )}
          <div className="flex-1">
            <h1 className="text-2xl font-bold text-[#212631] mb-1">
              {displayName}
            </h1>
            {user.position && (
              <p className="text-[#66686c]">{user.position}</p>
            )}
            <p className="text-sm text-[#8a8c91] mt-1">{user.email}</p>
          </div>
        </div>

        <div className="grid grid-cols-2 gap-4">
          <div className="bg-[#f5f6f8] rounded-lg p-4 border border-[#d8d9db]">
            <div className="flex items-center gap-2 mb-2">
              <Award className="w-4 h-4 text-[#5b6880]" />
              <span className="text-xs font-medium text-[#3d4657]">Received</span>
            </div>
            <p className="text-2xl font-bold text-[#212631]">—</p>
            <p className="text-xs text-[#8a8c91] mt-1">Kudos received</p>
          </div>
          <div className="bg-[#f5f6f8] rounded-lg p-4 border border-[#d8d9db]">
            <div className="flex items-center gap-2 mb-2">
              <TrendingUp className="w-4 h-4 text-[#5b6880]" />
              <span className="text-xs font-medium text-[#3d4657]">Given</span>
            </div>
            <p className="text-2xl font-bold text-[#212631]">—</p>
            <p className="text-xs text-[#8a8c91] mt-1">Kudos given</p>
          </div>
        </div>
      </div>

      <p className="text-center text-[#8a8c91] text-sm">
        <Link href="/feed" className="text-[#5b6880] hover:underline">
          Back to Feed
        </Link>
      </p>
    </div>
  );
}
